% Generated by: Seyed Mohammadali Rahmati
% Affiliation : Comparative Neuromechanics Lab,
%               School of Biological Sciences,
%               Georgia Institute of Technology, Atlanta, GA, USA
% Email       : smarahmati@gmail.com
%
% Description:
%   Runs the final model and kinematic analysis after landmark tuning.
%
%   Two cases are supported:
%       1) useFineTuning = true
%          Uses optimized/manual xopt values for anatomical landmark tuning.
%
%       2) useFineTuning = false
%          Sets xopt to zeros and uses the default landmark search-center
%          locations. This is useful when you want to run the model without
%          fine tuning.
% -------------------------------------------------------------------------

clear; clc;

tStart = tic;

%% -------------------------- User parameters -----------------------------

% Turn fine tuning on/off.
%   true  = use optimized/manual landmark offsets.
%   false = set all offsets to zero and run without fine tuning.
useFineTuning = true;

% Used only when useFineTuning = true.
% xoptSource options:
%   'auto'        : use O01_OptimizationResults.mat if available; otherwise manual vector
%   'O01_results' : force loading O01_OptimizationResults.mat
%   'manual'      : use the hard-coded vector in manualXopt()
xoptSource = 'auto';

optimizationResultsFile = 'O01_OptimizationResults.mat';

% B03 figures are useful for final inspection, so they are enabled here.
plotB03FiguresInO02 = true;

% Optional final workspace save.
saveFinalWorkspace = false;
finalWorkspaceFile = 'O02_FinalWorkspace.mat';

% Store settings in appdata because B01 starts with clear; clc.
O02Settings = struct();
O02Settings.useFineTuning = useFineTuning;
O02Settings.xoptSource = xoptSource;
O02Settings.optimizationResultsFile = optimizationResultsFile;
O02Settings.plotB03FiguresInO02 = plotB03FiguresInO02;
O02Settings.saveFinalWorkspace = saveFinalWorkspace;
O02Settings.finalWorkspaceFile = finalWorkspaceFile;
O02Settings.tStart = tStart;
setappdata(0, 'O02Settings', O02Settings);

%% -------------------------- Select model parameters ---------------------

if useFineTuning
    [xopt, xoptSourceUsed] = loadOptimizationVector(xoptSource, optimizationResultsFile);
else
    xopt = zeros(42, 1);
    xoptSourceUsed = 'fine tuning disabled: xopt = zeros(42,1)';
end

fprintf('O02 fine tuning enabled: %d\n', useFineTuning);
fprintf('O02 using xopt source  : %s\n', xoptSourceUsed);

%% -------------------------- Generate models and kinematics --------------

% These scripts use xopt to generate the anatomical landmarks and STL files.
% If useFineTuning = false, xopt is all zeros and the default landmark
% search-center locations are used.
Right_Left_Femur;
Right_Left_Tibia;
Right_Left_Foot;
Right_left_Pelvis;

B01_Registration_WithoutFlow_3DScale_WithMWF;

% B01 clears the workspace. Reload preserved O02 settings from appdata.
O02Settings = getappdata(0, 'O02Settings');
plotB03Figures = O02Settings.plotB03FiguresInO02;

B03_Kinematics_3D_And_Cycles_R1_MLaxis;

%% -------------------------- Optional save -------------------------------

O02Settings = getappdata(0, 'O02Settings');

if O02Settings.saveFinalWorkspace
    save(O02Settings.finalWorkspaceFile, '-v7.3');
    fprintf('Saved final workspace to %s.\n', O02Settings.finalWorkspaceFile);
end

elapsedTime = toc(O02Settings.tStart);
fprintf('O02 finished in %.2f seconds.\n', elapsedTime);
cleanupO02Settings();

%% -------------------------- Helper functions ----------------------------
function [xopt, sourceUsed] = loadOptimizationVector(xoptSource, optimizationResultsFile)
%LOADOPTIMIZATIONVECTOR Load optimized vector from O01 results or manual vector.

    switch lower(xoptSource)
        case 'auto'
            if isfile(optimizationResultsFile)
                [xopt, sourceUsed] = readO01Results(optimizationResultsFile);
            else
                xopt = manualXopt();
                sourceUsed = 'manual hard-coded xopt';
            end

        case 'o01_results'
            if ~isfile(optimizationResultsFile)
                error('Cannot find %s. Run O01_Optimization_Pattern first.', optimizationResultsFile);
            end
            [xopt, sourceUsed] = readO01Results(optimizationResultsFile);

        case 'manual'
            xopt = manualXopt();
            sourceUsed = 'manual hard-coded xopt';

        otherwise
            error('Unknown xoptSource: %s', xoptSource);
    end
end

function [xopt, sourceUsed] = readO01Results(resultsFile)
%READO01RESULTS Read xopt from O01_OptimizationResults.mat.

    loaded = load(resultsFile, 'OptimizationResults');

    if ~isfield(loaded, 'OptimizationResults')
        error('%s does not contain OptimizationResults.', resultsFile);
    end

    results = loaded.OptimizationResults;

    if isfield(results, 'xopt') && ~isempty(results.xopt)
        xopt = results.xopt;
    elseif isfield(results, 'x0') && ~isempty(results.x0)
        xopt = results.x0;
    elseif isfield(results, 'Progress') && isfield(results.Progress, 'x') && ~isempty(results.Progress.x)
        xopt = results.Progress.x;
    else
        error('%s does not contain OptimizationResults.xopt, x0, or Progress.x.', resultsFile);
    end

    sourceUsed = resultsFile;

    if isfield(results, 'stoppedByUser') && results.stoppedByUser
        fprintf('Loaded O01 result that was stopped by user.\n');
    end

    if isfield(results, 'interruptedOrFailed') && results.interruptedOrFailed
        fprintf('Loaded O01 result from an interrupted or failed optimization.\n');
    end
end

